"""
title: Ollama Usage Monitor
author: Johannes Faber (FAI-Solutions)
openwebui_id: 8b79ffd1-640d-4b43-b816-cc0071eb4e3b
description: A filter extension that shows Ollama cloud usage stats at the end of each LLM response.
requirements: cloudscraper
setup-guide: https://github.com/FAI-Solutions/open-webui-extensions/tree/main/ollama-usage-monitor
version: 0.5
"""

import asyncio
import json
import os
import time
from typing import Optional, Dict, List
from dataclasses import dataclass
from pydantic import BaseModel, Field
import cloudscraper


@dataclass
class UsageData:
    """Parsed usage data from Ollama Cloud"""

    session_percent: str = "N/A"
    session_reset: str = "N/A"
    weekly_percent: str = "N/A"
    weekly_reset: str = "N/A"
    error_message: str = ""

    def is_valid(self) -> bool:
        return self.session_percent != "N/A" or self.weekly_percent != "N/A"

    def format_compact(self) -> str:
        """Format usage data in compact form."""
        if self.error_message:
            return f"Error: {self.error_message}"

        weekly_pct = self.weekly_percent.replace(" used", "")
        session_pct = self.session_percent.replace(" used", "")
        weekly_reset = self.weekly_reset.replace("Resets in ", "")
        session_reset = self.session_reset.replace("Resets in ", "")

        return f"Weekly {weekly_pct} → Reset {weekly_reset} • run {session_pct} → Reset {session_reset}"


class OllamaUsageClient:
    """Cloudscraper to bypass Cloudflare protection"""

    BASE_URL = "https://ollama.com/settings"

    def __init__(
        self,
        name: str = "",
        secure_session: str = "",
        aid: str = "",
        cf_clearance: Optional[str] = None,
    ):
        self.name = name
        self.secure_session = secure_session
        self.aid = aid
        self.cf_clearance = cf_clearance

        self.scraper = cloudscraper.create_scraper()
        self._setup_cookies()

    def _setup_cookies(self):
        """Configure cookies for the session"""
        cookies = {
            "__Secure-session": self.secure_session,
            "aid": self.aid,
        }
        if self.cf_clearance:
            cookies["cf_clearance"] = self.cf_clearance

        if hasattr(self.scraper, "cookies"):
            self.scraper.cookies.update(cookies)

    def fetch_usage(self) -> UsageData:
        """Fetch usage data using cloudscraper"""
        try:
            headers = {
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
            }

            response = self.scraper.get(self.BASE_URL, headers=headers, timeout=15)
            response.raise_for_status()

            # Debug: Log first 500 chars
            print(f"DEBUG: Response status: {response.status_code}")
            print(f"DEBUG: First 500 chars: {response.text[:500]}")

            # Check if we got Cloudflare challenge
            if (
                "Just a moment" in response.text
                or "cf-browser-verification" in response.text
            ):
                return UsageData(
                    error_message="Cloudflare challenge still active - need fresh cf_clearance"
                )

            return self._parse_html(response.text)

        except Exception as e:
            return UsageData(
                error_message=f"Fetch error: {type(e).__name__}: {str(e)[:50]}"
            )

    def _parse_html(self, html: str) -> UsageData:
        """HTML to extract usage data"""
        try:
            from bs4 import BeautifulSoup
        except ImportError:
            return UsageData(error_message="BeautifulSoup not available")

        soup = BeautifulSoup(html, "html.parser")
        data = UsageData()

        cloud_usage = None
        for h2 in soup.find_all("h2"):
            if "Cloud Usage" in h2.get_text():
                cloud_usage = h2
                break

        all_h2 = [h.get_text(strip=True) for h in soup.find_all("h2")]
        print(f"DEBUG: All h2 tags found: {all_h2}")

        if not cloud_usage:
            page_title = soup.title.get_text() if soup.title else "No title"
            return UsageData(
                error_message=f"Cloud Usage h2 not found. Page title: {page_title}"
            )

        print(f"DEBUG: Found Cloud Usage element: {cloud_usage}")

        usage_divs = soup.find_all("div", class_="flex justify-between mb-2")
        print(f"DEBUG: Found {len(usage_divs)} usage divs")

        for div in usage_divs:
            spans = div.find_all("span")
            if len(spans) >= 2:
                label = spans[0].get_text(strip=True)
                value = spans[1].get_text(strip=True)
                print(f"DEBUG: Found usage div - label: '{label}', value: '{value}'")
                if label == "Session usage":
                    data.session_percent = value
                elif label == "Weekly usage":
                    data.weekly_percent = value

        time_divs = soup.find_all("div", class_="local-time")
        print(f"DEBUG: Found {len(time_divs)} time divs")

        reset_times = []
        for div in time_divs:
            text = div.get_text(strip=True)
            iso_time = div.get("data-time", "")
            reset_times.append((text, iso_time))
            print(f"DEBUG: Time div - text: '{text}', iso: '{iso_time}'")

        if len(reset_times) >= 1:
            data.session_reset = reset_times[0][0]
        if len(reset_times) >= 2:
            data.weekly_reset = reset_times[1][0]

        return data


class Filter:
    """Open WebUI Filter for monitoring Ollama usage"""

    class Valves(BaseModel):
        user_configs: str = Field(
            default="",
            description='JSON array: [{"name": "user1", "secure_session": "...", "aid": "...", "cf_clearance": "..."}]',
        )
        delay_seconds: float = Field(
            default=0.5,
            description="Delay before fetching to allow Ollama to update stats",
        )
        enabled: bool = Field(default=True, description="Enable/disable globally")
        debug_mode: bool = Field(default=False, description="Enable debug logging")

    def __init__(self):
        self.valves = self.Valves()
        self.toggle = True
        self.icon = (
            "https://cdn.jsdelivr.net/gh/twitter/twemoji@latest/assets/svg/2601.svg"
        )
        self._cache: Dict[str, tuple] = {}
        self._cache_ttl = 20

    def _get_clients(self) -> List[OllamaUsageClient]:
        """Initialize clients from valve configuration"""
        clients = []
        if self.valves.user_configs:
            try:
                configs = json.loads(self.valves.user_configs)
                for cfg in configs:
                    if cfg.get("enabled", True):
                        clients.append(
                            OllamaUsageClient(
                                name=cfg.get("name", ""),
                                secure_session=cfg.get("secure_session", ""),
                                aid=cfg.get("aid", ""),
                                cf_clearance=cfg.get("cf_clearance"),
                            )
                        )
            except (json.JSONDecodeError, TypeError) as e:
                print(f"Error parsing user_configs: {e}")
        return clients

    async def outlet(
        self, body: dict, __user__: Optional[dict] = None, **kwargs
    ) -> dict:
        """Append Ollama Cloud usage to the last assistant message"""
        if not self.valves.enabled:
            return body

        clients = self._get_clients()
        if not clients:
            return body

        await asyncio.sleep(self.valves.delay_seconds)

        usage_lines = []
        current_time = time.time()

        for i, client in enumerate(clients):
            name = client.name if client.name else f"user{i+1}"

            cache_key = f"{client.secure_session}:{client.aid}"
            if cache_key in self._cache:
                cached_data, cached_time = self._cache[cache_key]
                if current_time - cached_time < self._cache_ttl:
                    data = cached_data
                else:
                    data = client.fetch_usage()
                    self._cache[cache_key] = (data, current_time)
            else:
                data = client.fetch_usage()
                self._cache[cache_key] = (data, current_time)

            # Format output
            prefix = f"{name}: " if len(clients) > 1 else ""
            usage_lines.append(f"| {name}: {data.format_compact()} |")

        # Append to last assistant message
        if usage_lines:
            header = "------ ☁ Ollama Usage Monitor ------"
            usage_str = "\n".join([header] + usage_lines)

            for message in reversed(body.get("messages", [])):
                if message.get("role") == "assistant":
                    content = message.get("content", "")
                    if "☁ Ollama Usage Monitor" not in content:
                        message["content"] = f"{content}\n\n{usage_str}"
                    break
        return body
